import time


def normalize_pair(a, b) -> tuple:
    """Normalize a pair so (a, b) and (b, a) are equivalent."""
    return tuple(sorted([a, b]))


def pairs_from_clusters(clusters: list[set]) -> set[tuple]:
    """Convert list of clusters (sets of IDs) to set of normalized ID pairs."""
    pairs = set()
    for cluster in clusters:
        ids = sorted(cluster)
        for i in range(len(ids)):
            for j in range(i + 1, len(ids)):
                pairs.add(normalize_pair(ids[i], ids[j]))
    return pairs


def normalize_true_pairs(true_pairs: set) -> set[tuple]:
    """Normalize ground truth pairs for consistent comparison."""
    return {normalize_pair(a, b) for a, b in true_pairs}


def evaluate_pairs(predicted_pairs: set, true_pairs: set) -> dict:
    """Compute P/R/F1 from sets of ID pairs. Normalizes both sides."""
    predicted_pairs = {normalize_pair(*p) for p in predicted_pairs}
    true_pairs = {normalize_pair(*p) for p in true_pairs}
    tp = len(predicted_pairs & true_pairs)
    fp = len(predicted_pairs - true_pairs)
    fn = len(true_pairs - predicted_pairs)
    precision = tp / (tp + fp) if (tp + fp) > 0 else 0.0
    recall = tp / (tp + fn) if (tp + fn) > 0 else 0.0
    f1 = 2 * precision * recall / (precision + recall) if (precision + recall) > 0 else 0.0
    return {"precision": round(precision, 3), "recall": round(recall, 3), "f1": round(f1, 3),
            "tp": tp, "fp": fp, "fn": fn}


def evaluate_clusters(clusters, true_pairs):
    """Evaluate clusters by converting to pairwise matches, then computing P/R/F1."""
    return evaluate_pairs(pairs_from_clusters(clusters), true_pairs)


def time_it(func, *args, **kwargs):
    """Wall-clock timer. Returns (result, elapsed_seconds)."""
    start = time.perf_counter()
    result = func(*args, **kwargs)
    elapsed = time.perf_counter() - start
    return result, round(elapsed, 3)


def count_lines(filepath):
    """Count non-blank, non-comment lines in a file."""
    with open(filepath) as f:
        return sum(1 for line in f if line.strip() and not line.strip().startswith('#'))

